{
  "lean_declaration": "theorem simpleTransposition_isSwap {n : ℕ} (i : Fin (n - 1)) : (simpleTransposition i).IsSwap := by\n  have hne : (⟨i.val, Nat.lt_of_lt_of_le i.isLt (Nat.sub_le n 1)⟩ : Fin n) ≠ ⟨i.val + 1, by omega⟩ := by\n    intro h; have hval := congr_arg Fin.val h; omega\n  refine ⟨⟨i.val, Nat.lt_of_lt_of_le i.isLt (Nat.sub_le n 1)⟩, ⟨i.val + 1, by omega⟩, hne, ?_⟩\n  rfl",
  "declaration_name": "simpleTransposition_isSwap",
  "used_context": ["simpleTransposition", "Fin.val", "omega"],
  "notes": ["Proves that simpleTransposition i is a swap (2-cycle). Proof uses definition of simpleTransposition as Equiv.swap of two consecutive values."]
}
